    clientId,
    negativeItemId,
    itemType: item.itemType,
    creditorName: item.creditorName,
    dateOfFirstDelinquency,
    dofdConfidence: obsolescenceClock.confidence,
    fcraExpirationDate,
    reportingLimitYears,
    daysUntilExpiration,
    isPastLimit,
    bureau,

