export type CreditReportSource = 
  | 'identityiq'
  | 'smartcredit'
  | 'privacyguard'
  | 'myscoreiq'
  | 'creditkarma'
  | 'annualcreditreport'
  | 'experian'
  | 'transunion'
  | 'equifax'
  | 'unknown';

export interface SourceDetectionResult {
  source: CreditReportSource;
  confidence: 'high' | 'medium' | 'low';
  detectedBureau?: 'transunion' | 'experian' | 'equifax' | 'combined';
  signatures: string[];
}

// Signature patterns for each monitoring service
const SOURCE_SIGNATURES: Record<CreditReportSource, RegExp[]> = {
  identityiq: [
    /identityiq/i,
    /identity\s*iq/i,
    /idiq/i,
    /class="?iq-/i,
    /id="?iq-/i,
    /data-iq-/i,
    /IdentityIQ\.com/i,
    /Your\s+IdentityIQ\s+Report/i,
  ],
  smartcredit: [
    /smartcredit/i,
    /smart\s*credit/i,
    /class="?sc-/i,
    /smartcredit\.com/i,
    /SmartCredit\s+Report/i,
    /data-smartcredit/i,
  ],
  privacyguard: [
    /privacyguard/i,
    /privacy\s*guard/i,
    /class="?pg-/i,
    /privacyguard\.com/i,
    /PrivacyGuard\s+Report/i,
  ],
  myscoreiq: [
    /myscoreiq/i,
    /my\s*score\s*iq/i,
