  ],
  creditkarma: [
    /creditkarma/i,
    /credit\s*karma/i,
    /creditkarma\.com/i,
    /class="?ck-/i,
  ],
  annualcreditreport: [
    /annualcreditreport/i,
    /annual\s*credit\s*report/i,
    /annualcreditreport\.com/i,
    /Free\s+Annual\s+Credit\s+Report/i,
