    /centralsource/i,
  ],
  experian: [
    /experian\.com/i,
    /Experian\s+Credit\s+Report/i,
    /class="?experian-/i,
    /class="?ex-/i,
    /data-experian/i,
    /FICO.*Score.*8/i,
    /Experian\s+Member/i,
    /experian\.com\/consumer/i,
    /Potentially\s+Negative\s+Information/i,
    /Your\s+Experian\s+Credit\s+Report/i,
  ],
  transunion: [
    /transunion\.com/i,
    /TransUnion\s+Credit\s+Report/i,
    /class="?tu-/i,
    /data-transunion/i,
